import{_ as i,o as a,c as r,ae as t}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Advertising Identifiers for Attribution","description":"","frontmatter":{"title":"Advertising Identifiers for Attribution","slug":"advertising-identifiers-for-attribution"},"headers":[],"relativePath":"marketer-hub/advertising-identifiers-for-attribution.md","filePath":"marketer-hub/advertising-identifiers-for-attribution.md"}'),o={name:"marketer-hub/advertising-identifiers-for-attribution.md"};function n(s,e,d,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[t('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch supports the following advertising identifiers in Branch Links on click, install, and other event requests. When the same identifier is available on click and install, Branch can perform attribution by matching this value through Identifier Matching.</p><h2 id="types-of-identifiers" tabindex="-1">Types of Identifiers <a class="header-anchor" href="#types-of-identifiers" aria-label="Permalink to &quot;Types of Identifiers&quot;">​</a></h2><h3 id="ios-identifiers" tabindex="-1">iOS Identifiers <a class="header-anchor" href="#ios-identifiers" aria-label="Permalink to &quot;iOS Identifiers&quot;">​</a></h3><p><strong>Advertising Identifiers</strong></p><h4 id="ios-idfa" tabindex="-1">iOS IDFA <a class="header-anchor" href="#ios-idfa" aria-label="Permalink to &quot;iOS IDFA&quot;">​</a></h4><p>In the absence of a valid IDFA, and where permitted under Apple&#39;s policies on tracking, Branch automatically falls back to probabilistic modeling to perform attribution (<a href="./predictive-modeling.html">Predictive Modeling</a>), and automatically assigns its own install-level identifier for future measurement of these installs, not used for ad partner (3p) traffic. This is existing behavior, however, it does require that partners pass the Device IP and User Agent to be used for modeling decisions.</p><p>Apple introduced its Identifier for Advertisers (IDFA) with iOS 6.0 primarily through the ASIdentifierManager class in iOS, which provides apps with access to an identifier that you can use for serving advertisements, as well as a flag that indicates if a user has enabled the Limit Ad Tracking feature. The IDFA value is an alphanumeric string that is unique to each device, and uses an upper case-format with hyphens (for example, <code>AAAAAAAAA-BBBB-CCCC-1111-222222220000</code>).</p><ul><li>Branch log-level parameter: <code>user_data_idfa</code></li><li>Branch postback macro: <code>${(user_data.idfa)!}</code> and <code>&lt;#if (user_data.limit_ad_tracking)! &gt;0&lt;#else&gt;1</code></li></ul><p>If you’re using the <code>${(user_data.idfa)!}</code> macro in a postback URL, then you must specify the <code>&lt;#if (user_data.limit_ad_tracking)! &gt;0&lt;#else&gt;1</code> macro to indicate if the user has enabled the Limit Ad Tracking feature (where 0 is limited). Or if the user has enabled this feature, you can set the ios_ad_tracking_disabled parameter to 1.</p><p>If your SDK implementation does not collect IDFA on install (first “app open” event) and with post-install/in-app events, then you cannot use it for attribution by matching the value specified on click with the value specified on install (or some other event).</p><h3 id="android-identifiers" tabindex="-1">Android Identifiers <a class="header-anchor" href="#android-identifiers" aria-label="Permalink to &quot;Android Identifiers&quot;">​</a></h3><h4 id="google-aaid" tabindex="-1">Google AAID <a class="header-anchor" href="#google-aaid" aria-label="Permalink to &quot;Google AAID&quot;">​</a></h4><p>The <a href="https://developer.android.com/google/play-services/id.html" target="_blank" rel="noreferrer">Google Advertising Identifier (AAID)</a> is a unique, user-specific, and resettable ID for advertising provided by Google Play services, which exposes an API for accessing the advertising ID of the user as a string, in the universally unique identifier (UUID) format similar to <code>38400000-8cf0-11bd-b23e-10b96e40000d</code>.</p><ul><li>Branch log-level parameter: <code>user_data_aaid</code></li><li>Branch postback macro: <code>${(user_data.aaid)!}</code></li></ul><h4 id="android-oaid" tabindex="-1">Android OAID <a class="header-anchor" href="#android-oaid" aria-label="Permalink to &quot;Android OAID&quot;">​</a></h4><p>The Open Anonymous Device Identifier (OAID) is used for advertising purposes in place of the non-supported Google Advertising ID for specific device manufacturers. The Branch SDK collects OAID and uses it for attribution on clicks and impressions.</p><ul><li>Branch log-level parameter: <code>user_data_oaid</code></li><li>Branch postback macro: <code>${(user_data.oaid)!}</code></li></ul><h4 id="legacy-other-identifiers" tabindex="-1">Legacy &amp; Other Identifiers <a class="header-anchor" href="#legacy-other-identifiers" aria-label="Permalink to &quot;Legacy &amp; Other Identifiers&quot;">​</a></h4><p>While we rely first and foremost on advertising identifiers for attribution, there are cases in which advertising identifiers are not available. This includes legacy versions that do not support advertising identifiers and users downloading from non-Google android app stores. If an advertising identifier is not available, we rely on the following device identifiers for attribution.</p><p><strong>Android ID</strong></p><p>The <a href="http://developer.android.com/reference/android/provider/Settings.Secure.html#ANDROID_ID" target="_blank" rel="noreferrer">ANDROID ID</a> for Android devices is a 64-bit number (as a hex string) that is randomly generated on the first boot of a device and typically remains constant for the lifetime of the device. This value is formatted as lower case.</p><ul><li>Branch log-level parameter: <code>user_data.android_id</code></li><li>Branch postback macro: <code>${(user_data.android_id)!}</code></li></ul><h3 id="amazon-identifiers" tabindex="-1">Amazon Identifiers <a class="header-anchor" href="#amazon-identifiers" aria-label="Permalink to &quot;Amazon Identifiers&quot;">​</a></h3><h4 id="fire-id" tabindex="-1">Fire ID <a class="header-anchor" href="#fire-id" aria-label="Permalink to &quot;Fire ID&quot;">​</a></h4><p>The <a href="https://www.developer.amazon.com/docs/policy-center/advertising-id.html" target="_blank" rel="noreferrer">Amazon Fire ID</a> is a user-resettable, unique identifier that helps protect the privacy of the user. If you collect information about a user’s behavior to display interest-based ads, or to generate analytics, you must use the Advertising ID; no other identifier or tracking method may be used. Users can reset the Advertising ID or opt out of interest-based ads altogether.</p><ul><li>Branch log-level parameter: <code>user_data.aaid</code></li><li>Branch postback macro: <code>${(user_data.aaid)!}</code></li></ul><h3 id="windows-phone-identifiers" tabindex="-1">Windows Phone Identifiers <a class="header-anchor" href="#windows-phone-identifiers" aria-label="Permalink to &quot;Windows Phone Identifiers&quot;">​</a></h3><h4 id="windows-aid" tabindex="-1">Windows AID <a class="header-anchor" href="#windows-aid" aria-label="Permalink to &quot;Windows AID&quot;">​</a></h4><p>The <a href="http://msdn.microsoft.com/en-us/library/windows/apps/windows.system.userprofile.advertisingmanager.advertisingid.aspx" target="_blank" rel="noreferrer">Windows advertising identifier (AID)</a> is a unique, user and device-specific, and resettable ID for advertising represented as an alphanumeric string formatted as upper case without colons (for example, <code>AAAAAABBBBCCCC111122222222222</code>). When the advertising ID feature is disabled, this value is an empty string.</p><ul><li>Branch log-level parameter: <code>user_data_windows_aid</code></li><li>Branch postback macro: <code>${(user_data.windows_aid)!}</code></li></ul><h3 id="user-identifiers" tabindex="-1">User Identifiers <a class="header-anchor" href="#user-identifiers" aria-label="Permalink to &quot;User Identifiers&quot;">​</a></h3><h4 id="user-id" tabindex="-1">User ID <a class="header-anchor" href="#user-id" aria-label="Permalink to &quot;User ID&quot;">​</a></h4><p>The user ID generated by app developers (advertisers) is the same ID of the user in their system. The user_id only works with cross-promo internal campaigns because third-party advertising partners cannot access or replicate this value (as they can with the other Android or iOS identifiers mentioned previously).</p><ul><li>Branch log-level parameter: <code>user_data_developer_identity</code></li><li>Branch postback macro: <code>${(user_data.developer_identity)!}</code></li></ul>',35)])])}const p=i(o,[["render",n]]);export{u as __pageData,p as default};
